  "Longest run": { eng: "Longest run", deu: "Längster Run", esp: "Partida más larga", fra: "Partie la plus longue", ita: "Partita più lunga", jpn: "最長のラン", kor: "가장 긴 런", pol: "Najdłuższy przebieg", ptb: "Partida mais longa", rus: "Самый длинный забег", spa: "Partida más larga", tha: "การเล่นที่ยาวที่สุด", tur: "En uzun oyun", zhs: "最长的对局" },
  "Most Deadly Encounters": { eng: "Most Deadly Encounters", deu: "Tödlichste Begegnungen", esp: "Encuentros más mortales", fra: "Rencontres les plus meurtrières", ita: "Incontri più mortali", jpn: "最も死者を出した遭遇", kor: "가장 위험한 조우", pol: "Najbardziej zabójcze spotkania", ptb: "Encontros mais mortais", rus: "Самые опасные встречи", spa: "Encuentros más mortales", tha: "การเผชิญหน้าที่ร้ายแรงที่สุด", tur: "En öldürücü karşılaşmalar", zhs: "最致命的遭遇战" },
  "Most-removed cards": { eng: "Most-removed cards", deu: "Am häufigsten entfernte Karten", esp: "Cartas más eliminadas", fra: "Cartes les plus retirées", ita: "Carte più rimosse", jpn: "最も除去されたカード", kor: "가장 많이 제거된 카드", pol: "Najczęściej usuwane karty", ptb: "Cartas mais removidas", rus: "Чаще всего удаляемые карты", spa: "Cartas más eliminadas", tha: "การ์ดที่ถูกลบมากที่สุด", tur: "En çok kaldırılan kartlar", zhs: "最常被移除的卡牌" },
  "Network error during upload": { eng: "Network error during upload", deu: "Netzwerkfehler beim Hochladen", esp: "Error de red durante la subida", fra: "Erreur réseau pendant l'envoi", ita: "Errore di rete durante il caricamento", jpn: "アップロード中にネットワークエラーが発生しました", kor: "업로드 중 네트워크 오류", pol: "Błąd sieci podczas przesyłania", ptb: "Erro de rede durante o envio", rus: "Сетевая ошибка при загрузке", spa: "Error de red durante la subida", tha: "เกิดข้อผิดพลาดของเครือข่ายระหว่างการอัปโหลด", tur: "Yükleme sırasında ağ hatası", zhs: "上传时发生网络错误" },
  "No cards match your filters.": { eng: "No cards match your filters.", deu: "Keine Karten entsprechen deinen Filtern.", esp: "Ninguna carta coincide con tus filtros.", fra: "Aucune carte ne correspond à vos filtres.", ita: "Nessuna carta corrisponde ai tuoi filtri.", jpn: "フィルターに一致するカードはありません。", kor: "필터와 일치하는 카드가 없습니다.", pol: "Żadna karta nie pasuje do Twoich filtrów.", ptb: "Nenhuma carta corresponde aos seus filtros.", rus: "Нет карт, соответствующих вашим фильтрам.", spa: "Ninguna carta coincide con tus filtros.", tha: "ไม่มีการ์ดที่ตรงกับตัวกรองของคุณ", tur: "Filtrelerinize uyan kart yok.", zhs: "没有卡牌符合你的筛选条件。" },
  "No email address (unless you voluntarily provide one as a contact value when submitting feedback).": { eng: "No email address (unless you voluntarily provide one as a contact value when submitting feedback).", deu: "Keine E-Mail-Adresse (es sei denn, du gibst freiwillig eine als Kontaktangabe beim Einreichen von Feedback an).", esp: "Sin dirección de correo (a menos que proporciones una voluntariamente como valor de contacto al enviar comentarios).", fra: "Aucune adresse e-mail (sauf si vous en fournissez une volontairement comme moyen de contact lors de l'envoi d'un retour).", ita: "Nessun indirizzo e-mail (a meno che tu non ne fornisca uno volontariamente come contatto durante l'invio del feedback).", jpn: "メールアドレスは収集しません（フィードバック送信時に連絡先として自発的に入力した場合を除く）。", kor: "이메일 주소 없음(피드백을 제출할 때 연락처 값으로 자발적으로 제공하는 경우 제외).", pol: "Brak adresu e-mail (chyba że dobrowolnie podasz go jako dane kontaktowe podczas przesyłania opinii).", ptb: "Nenhum endereço de e-mail (a menos que você forneça um voluntariamente como valor de contato ao enviar feedback).", rus: "Никаких адресов эл. почты (если только вы добровольно не укажете его как контакт при отправке отзыва).", spa: "Sin dirección de correo (a menos que proporciones una voluntariamente como valor de contacto al enviar comentarios).", tha: "ไม่มีที่อยู่อีเมล (เว้นแต่คุณจะให้ไว้โดยสมัครใจเป็นข้อมูลติดต่อเมื่อส่งความคิดเห็น)", tur: "E-posta adresi yok (geri bildirim gönderirken iletişim değeri olarak gönüllü sağlamanız hariç).", zhs: "不收集电子邮件地址（除非你在提交反馈时自愿将其作为联系方式提供）。" },
