  "or open an issue on": { eng: "or open an issue on", deu: "oder erstelle ein Issue auf", esp: "o abre una incidencia en", fra: "ou ouvrez un ticket sur", ita: "o apri una issue su", jpn: "または、以下でイシューを作成してください：", kor: "또는 다음에서 이슈를 등록하세요:", pol: "lub zgłoś problem na", ptb: "ou abra uma issue no", rus: "или создайте issue на", spa: "o abre una incidencia en", tha: "หรือเปิด issue ที่", tur: "veya şurada bir issue aç:", zhs: "或在以下位置提交 issue" },
